import { computePairAddress } from '@uniswap/v2-sdk';
import { Percent, Token, V2_FACTORY_ADDRESSES } from '@vanadex/sdk-core';
import { useWeb3React } from '@web3-react/core';
import { L2_CHAIN_IDS } from 'constants/chains';
import { L2_DEADLINE_FROM_NOW } from 'constants/misc';
import JSBI from 'jsbi';
import { useCallback, useMemo } from 'react';
import { useAppDispatch, useAppSelector } from 'state/hooks';
import { UserAddedToken } from 'types/tokens';
import { BASES_TO_TRACK_LIQUIDITY_FOR, PINNED_PAIRS } from '../../constants/routing';
import { useDefaultActiveTokens } from '../../hooks/Tokens';
import { addSerializedPair, addSerializedToken, updateHideClosedPositions, updateUserDeadline, updateUserLocale, updateUserSlippageTolerance } from './reducer';
import { SlippageTolerance } from './types';
export function serializeToken(token) {
    return {
        chainId: token.chainId,
        address: token.address,
        decimals: token.decimals,
        symbol: token.symbol,
        name: token.name
    };
}
export function deserializeToken(serializedToken, Class = Token) {
    return new Class(serializedToken.chainId, serializedToken.address, serializedToken.decimals, serializedToken.symbol, serializedToken.name);
}
export function useUserLocale() {
    return useAppSelector((state)=>state.user.userLocale);
}
export function useUserLocaleManager() {
    const dispatch = useAppDispatch();
    const locale = useUserLocale();
    const setLocale = useCallback((newLocale)=>{
        dispatch(updateUserLocale({
            userLocale: newLocale
        }));
    }, [
        dispatch
    ]);
    return [
        locale,
        setLocale
    ];
}
/**
 * Return the user's slippage tolerance, from the redux store, and a function to update the slippage tolerance
 */ export function useUserSlippageTolerance() {
    const userSlippageToleranceRaw = useAppSelector((state)=>{
        return state.user.userSlippageTolerance;
    });
    // TODO(WEB-1985): Keep `userSlippageTolerance` as Percent in Redux store and remove this conversion
    const userSlippageTolerance = useMemo(()=>userSlippageToleranceRaw === SlippageTolerance.Auto ? SlippageTolerance.Auto : new Percent(userSlippageToleranceRaw, 10000), [
        userSlippageToleranceRaw
    ]);
    const dispatch = useAppDispatch();
    const setUserSlippageTolerance = useCallback((userSlippageTolerance)=>{
        let value;
        try {
            value = userSlippageTolerance === SlippageTolerance.Auto ? SlippageTolerance.Auto : JSBI.toNumber(userSlippageTolerance.multiply(10000).quotient);
        } catch (error) {
            value = SlippageTolerance.Auto;
        }
        dispatch(updateUserSlippageTolerance({
            userSlippageTolerance: value
        }));
    }, [
        dispatch
    ]);
    return [
        userSlippageTolerance,
        setUserSlippageTolerance
    ];
}
/**
 *Returns user slippage tolerance, replacing the auto with a default value
 * @param defaultSlippageTolerance the value to replace auto with
 */ export function useUserSlippageToleranceWithDefault(defaultSlippageTolerance) {
    const [allowedSlippage] = useUserSlippageTolerance();
    return allowedSlippage === SlippageTolerance.Auto ? defaultSlippageTolerance : allowedSlippage;
}
export function useUserHideClosedPositions() {
    const dispatch = useAppDispatch();
    const hideClosedPositions = useAppSelector((state)=>state.user.userHideClosedPositions);
    const setHideClosedPositions = useCallback((newHideClosedPositions)=>{
        dispatch(updateHideClosedPositions({
            userHideClosedPositions: newHideClosedPositions
        }));
    }, [
        dispatch
    ]);
    return [
        hideClosedPositions,
        setHideClosedPositions
    ];
}
export function useUserTransactionTTL() {
    const { chainId } = useWeb3React();
    const dispatch = useAppDispatch();
    const userDeadline = useAppSelector((state)=>state.user.userDeadline);
    const onL2 = Boolean(chainId && L2_CHAIN_IDS.includes(chainId));
    const deadline = onL2 ? L2_DEADLINE_FROM_NOW : userDeadline;
    const setUserDeadline = useCallback((userDeadline)=>{
        dispatch(updateUserDeadline({
            userDeadline
        }));
    }, [
        dispatch
    ]);
    return [
        deadline,
        setUserDeadline
    ];
}
export function useAddUserToken() {
    const dispatch = useAppDispatch();
    return useCallback((token)=>{
        dispatch(addSerializedToken({
            serializedToken: serializeToken(token)
        }));
    }, [
        dispatch
    ]);
}
function useUserAddedTokensOnChain(chainId) {
    const serializedTokensMap = useAppSelector(({ user: { tokens } })=>tokens);
    return useMemo(()=>{
        if (!chainId) return [];
        const tokenMap = serializedTokensMap?.[chainId] ? Object.values(serializedTokensMap[chainId]).map((value)=>deserializeToken(value, UserAddedToken)) : [];
        return tokenMap;
    }, [
        serializedTokensMap,
        chainId
    ]);
}
export function useUserAddedTokens() {
    return useUserAddedTokensOnChain(useWeb3React().chainId);
}
function serializePair(pair) {
    return {
        token0: serializeToken(pair.token0),
        token1: serializeToken(pair.token1)
    };
}
export function usePairAdder() {
    const dispatch = useAppDispatch();
    return useCallback((pair)=>{
        dispatch(addSerializedPair({
            serializedPair: serializePair(pair)
        }));
    }, [
        dispatch
    ]);
}
/**
 * Given two tokens return the liquidity token that represents its liquidity shares
 * @param tokenA one of the two tokens
 * @param tokenB the other token
 */ export function toV2LiquidityToken([tokenA, tokenB]) {
    if (tokenA.chainId !== tokenB.chainId) throw new Error('Not matching chain IDs');
    if (tokenA.equals(tokenB)) throw new Error('Tokens cannot be equal');
    if (!V2_FACTORY_ADDRESSES[tokenA.chainId]) throw new Error('No V2 factory address on this chain');
    return new Token(tokenA.chainId, computePairAddress({
        factoryAddress: V2_FACTORY_ADDRESSES[tokenA.chainId],
        tokenA,
        tokenB
    }), 18, 'UNI-V2', 'Uniswap V2');
}
/**
 * Returns all the pairs of tokens that are tracked by the user for the current chain ID.
 */ export function useTrackedTokenPairs() {
    const { chainId } = useWeb3React();
    const tokens = useDefaultActiveTokens(chainId);
    // pinned pairs
    const pinnedPairs = useMemo(()=>chainId ? PINNED_PAIRS[chainId] ?? [] : [], [
        chainId
    ]);
    // pairs for every token against every base
    const generatedPairs = useMemo(()=>chainId ? Object.keys(tokens).flatMap((tokenAddress)=>{
            const token = tokens[tokenAddress];
            // for each token on the current chain,
            return(// loop though all bases on the current chain
            (BASES_TO_TRACK_LIQUIDITY_FOR[chainId] ?? [])// to construct pairs of the given token with each base
            .map((base)=>{
                if (base.address === token.address) {
                    return null;
                } else {
                    return [
                        base,
                        token
                    ];
                }
            }).filter((p)=>p !== null));
        }) : [], [
        tokens,
        chainId
    ]);
    // pairs saved by users
    const savedSerializedPairs = useAppSelector(({ user: { pairs } })=>pairs);
    const userPairs = useMemo(()=>{
        if (!chainId || !savedSerializedPairs) return [];
        const forChain = savedSerializedPairs[chainId];
        if (!forChain) return [];
        return Object.keys(forChain).map((pairId)=>{
            return [
                deserializeToken(forChain[pairId].token0),
                deserializeToken(forChain[pairId].token1)
            ];
        });
    }, [
        savedSerializedPairs,
        chainId
    ]);
    const combinedList = useMemo(()=>userPairs.concat(generatedPairs).concat(pinnedPairs), [
        generatedPairs,
        pinnedPairs,
        userPairs
    ]);
    return useMemo(()=>{
        // dedupes pairs of tokens in the combined list
        const keyed = combinedList.reduce((memo, [tokenA, tokenB])=>{
            const sorted = tokenA.sortsBefore(tokenB);
            const key = sorted ? `${tokenA.address}:${tokenB.address}` : `${tokenB.address}:${tokenA.address}`;
            if (memo[key]) return memo;
            memo[key] = sorted ? [
                tokenA,
                tokenB
            ] : [
                tokenB,
                tokenA
            ];
            return memo;
        }, {});
        return Object.keys(keyed).map((key)=>keyed[key]);
    }, [
        combinedList
    ]);
}
