import IUniswapV2PairJson from "@uniswap/v2-core/build/IUniswapV2Pair.json";
import IUniswapV2Router02Json from "@uniswap/v2-periphery/build/IUniswapV2Router02.json";
import UniswapInterfaceMulticallJson from "@uniswap/v3-periphery/artifacts/contracts/lens/UniswapInterfaceMulticall.sol/UniswapInterfaceMulticall.json";
import NonfungiblePositionManagerJson from "@uniswap/v3-periphery/artifacts/contracts/NonfungiblePositionManager.sol/NonfungiblePositionManager.json";
import V3MigratorJson from "@uniswap/v3-periphery/artifacts/contracts/V3Migrator.sol/V3Migrator.json";
import { ARGENT_WALLET_DETECTOR_ADDRESS, ChainId, ENS_REGISTRAR_ADDRESSES, MULTICALL_ADDRESSES, NONFUNGIBLE_POSITION_MANAGER_ADDRESSES, V2_ROUTER_ADDRESS, V3_MIGRATOR_ADDRESSES } from "@vanadex/sdk-core";
import { useWeb3React } from "@web3-react/core";
import ARGENT_WALLET_DETECTOR_ABI from "abis/argent-wallet-detector.json";
import EIP_2612 from "abis/eip_2612.json";
import ENS_PUBLIC_RESOLVER_ABI from "abis/ens-public-resolver.json";
import ENS_ABI from "abis/ens-registrar.json";
import ERC20_ABI from "abis/erc20.json";
import ERC20_BYTES32_ABI from "abis/erc20_bytes32.json";
import ERC721_ABI from "abis/erc721.json";
import ERC1155_ABI from "abis/erc1155.json";
import WETH_ABI from "abis/weth.json";
import { RPC_PROVIDERS } from "constants/providers";
import { WRAPPED_NATIVE_CURRENCY } from "constants/tokens";
import { useMemo } from "react";
import { getContract } from "utils";
const { abi: IUniswapV2PairABI } = IUniswapV2PairJson;
const { abi: IUniswapV2Router02ABI } = IUniswapV2Router02Json;
const { abi: MulticallABI } = UniswapInterfaceMulticallJson;
const { abi: NFTPositionManagerABI } = NonfungiblePositionManagerJson;
const { abi: V2MigratorABI } = V3MigratorJson;
// returns null on errors
export function useContract(addressOrAddressMap, ABI, withSignerIfPossible = true) {
    const { provider, account, chainId } = useWeb3React();
    return useMemo(()=>{
        if (!addressOrAddressMap || !ABI || !provider || !chainId) return null;
        let address;
        if (typeof addressOrAddressMap === "string") address = addressOrAddressMap;
        else address = addressOrAddressMap[chainId];
        if (!address) return null;
        try {
            return getContract(address, ABI, provider, withSignerIfPossible && account ? account : undefined);
        } catch (error) {
            console.error("Failed to get contract", error);
            return null;
        }
    }, [
        addressOrAddressMap,
        ABI,
        provider,
        chainId,
        withSignerIfPossible,
        account
    ]);
}
function useMainnetContract(address, ABI) {
    const { chainId, provider } = useWeb3React();
    const isMainnet = chainId === ChainId.MAINNET;
    const contract = useContract(isMainnet ? address : undefined, ABI, false);
    const mainnetProvider = chainId === ChainId.MAINNET && provider !== undefined ? provider : RPC_PROVIDERS[ChainId.MAINNET];
    return useMemo(()=>{
        if (isMainnet) return contract;
        if (!address) return null;
        try {
            return getContract(address, ABI, mainnetProvider);
        } catch (error) {
            console.error("Failed to get mainnet contract", error);
            return null;
        }
    }, [
        isMainnet,
        contract,
        address,
        ABI,
        mainnetProvider
    ]);
}
export function useV2MigratorContract() {
    return useContract(V3_MIGRATOR_ADDRESSES, V2MigratorABI, true);
}
export function useTokenContract(tokenAddress, withSignerIfPossible) {
    return useContract(tokenAddress, ERC20_ABI, withSignerIfPossible);
}
export function useWETHContract(withSignerIfPossible) {
    const { chainId } = useWeb3React();
    return useContract(chainId ? WRAPPED_NATIVE_CURRENCY[chainId]?.address : undefined, WETH_ABI, withSignerIfPossible);
}
export function useERC721Contract(nftAddress) {
    return useContract(nftAddress, ERC721_ABI, false);
}
export function useERC1155Contract(nftAddress) {
    return useContract(nftAddress, ERC1155_ABI, false);
}
export function useArgentWalletDetectorContract() {
    return useContract(ARGENT_WALLET_DETECTOR_ADDRESS, ARGENT_WALLET_DETECTOR_ABI, false);
}
export function useENSRegistrarContract() {
    return useMainnetContract(ENS_REGISTRAR_ADDRESSES[ChainId.MAINNET], ENS_ABI);
}
export function useENSResolverContract(address) {
    return useMainnetContract(address, ENS_PUBLIC_RESOLVER_ABI);
}
export function useBytes32TokenContract(tokenAddress, withSignerIfPossible) {
    return useContract(tokenAddress, ERC20_BYTES32_ABI, withSignerIfPossible);
}
export function useEIP2612Contract(tokenAddress) {
    return useContract(tokenAddress, EIP_2612, false);
}
export function usePairContract(pairAddress, withSignerIfPossible) {
    return useContract(pairAddress, IUniswapV2PairABI, withSignerIfPossible);
}
export function useV2RouterContract() {
    return useContract(V2_ROUTER_ADDRESS, IUniswapV2Router02ABI, true);
}
export function useInterfaceMulticall() {
    return useContract(MULTICALL_ADDRESSES, MulticallABI, false);
}
export function useMainnetInterfaceMulticall() {
    return useMainnetContract(MULTICALL_ADDRESSES[ChainId.MAINNET], MulticallABI);
}
export function useV3NFTPositionManagerContract(withSignerIfPossible) {
    const contract = useContract(NONFUNGIBLE_POSITION_MANAGER_ADDRESSES, NFTPositionManagerABI, withSignerIfPossible);
    return contract;
}
