import { useMemo } from 'react';
/** Sorts tokens by query, giving precedence to exact matches and partial matches. */ export function useSortTokensByQuery(query, tokens) {
    return useMemo(()=>{
        if (!tokens) {
            return [];
        }
        const matches = query.toLowerCase().split(/\s+/).filter((s)=>s.length > 0);
        if (matches.length > 1) {
            return tokens;
        }
        const exactMatches = [];
        const symbolSubtrings = [];
        const rest = [];
        // sort tokens by exact match -> subtring on symbol match -> rest
        const trimmedQuery = query.toLowerCase().trim();
        tokens.map((token)=>{
            const symbol = token.symbol?.toLowerCase();
            if (symbol === matches[0]) {
                return exactMatches.push(token);
            } else if (symbol?.startsWith(trimmedQuery)) {
                return symbolSubtrings.push(token);
            } else {
                return rest.push(token);
            }
        });
        return [
            ...exactMatches,
            ...symbolSubtrings,
            ...rest
        ];
    }, [
        tokens,
        query
    ]);
}
