import { ChainId } from '@vanadex/sdk-core';
import useHttpLocations from 'hooks/useHttpLocations';
import { useMemo } from 'react';
import { isAddress } from 'utils';
import VanaLogo from '../../assets/images/vana.png';
import AvaxLogo from '../../assets/svg/avax_logo.svg';
import BnbLogo from '../../assets/svg/bnb-logo.svg';
import CeloLogo from '../../assets/svg/celo_logo.svg';
import MaticLogo from '../../assets/svg/matic-token-icon.svg';
import { isCelo, NATIVE_CHAIN_ID, nativeOnChain } from '../../constants/tokens';
export function chainIdToNetworkName(networkId) {
    switch(networkId){
        case ChainId.MAINNET:
            return 'ethereum';
        case ChainId.ARBITRUM_ONE:
            return 'arbitrum';
        case ChainId.OPTIMISM:
            return 'optimism';
        case ChainId.POLYGON:
            return 'polygon';
        case ChainId.BNB:
            return 'smartchain';
        case ChainId.CELO:
            return 'celo';
        case ChainId.AVALANCHE:
            return 'avalanchec';
        case ChainId.VANA:
            return 'vana';
        case ChainId.VANA_MOKSHA:
            return 'vana';
        default:
            return 'ethereum';
    }
}
export function getNativeLogoURI(chainId = ChainId.VANA) {
    switch(chainId){
        case ChainId.POLYGON:
        case ChainId.POLYGON_MUMBAI:
            return MaticLogo;
        case ChainId.BNB:
            return BnbLogo;
        case ChainId.CELO:
        case ChainId.CELO_ALFAJORES:
            return CeloLogo;
        case ChainId.AVALANCHE:
            return AvaxLogo;
        case ChainId.VANA:
            return VanaLogo;
        case ChainId.VANA_MOKSHA:
            return VanaLogo;
        default:
            return VanaLogo;
    }
}
function getTokenLogoURI(address, chainId = ChainId.MAINNET) {
    const networkName = chainIdToNetworkName(chainId);
    const networksWithUrls = [
        ChainId.ARBITRUM_ONE,
        ChainId.MAINNET,
        ChainId.OPTIMISM,
        ChainId.BNB,
        ChainId.AVALANCHE
    ];
    if (isCelo(chainId) && address === nativeOnChain(chainId).wrapped.address) {
        return CeloLogo;
    }
    if (networksWithUrls.includes(chainId)) {
        return `https://raw.githubusercontent.com/Uniswap/assets/master/blockchains/${networkName}/assets/${address}/logo.png`;
    }
}
export default function useCurrencyLogoURIs(currency) {
    const locations = useHttpLocations(currency?.logoURI);
    return useMemo(()=>{
        const logoURIs = [
            ...locations
        ];
        if (currency) {
            if (currency.isNative || currency.address === NATIVE_CHAIN_ID) {
                logoURIs.push(getNativeLogoURI(currency.chainId));
            } else if (currency.isToken || currency.address) {
                const checksummedAddress = isAddress(currency.address);
                const logoURI = checksummedAddress && getTokenLogoURI(checksummedAddress, currency.chainId);
                if (logoURI) {
                    logoURIs.push(logoURI);
                }
            }
        }
        return logoURIs;
    }, [
        currency,
        locations
    ]);
}
