import { useWeb3React } from "@web3-react/core";
import { WRAPPED_NATIVE_CURRENCY } from "constants/tokens";
import { useMemo } from "react";
import { RouterPreference } from "state/routing/types";
import { useRoutingAPITrade } from "state/routing/useRoutingAPITrade";
import useAutoRouterSupported from "./useAutoRouterSupported";
import useDebounce from "./useDebounce";
// Prevents excessive quote requests between keystrokes.
const DEBOUNCE_TIME = 350;
/**
 * Returns the debounced v2+v3 trade for a desired swap.
 * @param tradeType whether the swap is an exact in/out
 * @param amountSpecified the exact amount to swap in/out
 * @param otherCurrency the desired output/payment currency
 * @param routerPreferenceOverride force useRoutingAPITrade to use a specific RouterPreference
 * @param account the connected address
 *
 */ export function useDebouncedTrade(tradeType, amountSpecified, otherCurrency, routerPreferenceOverride, account, inputTax, outputTax) {
    const { chainId } = useWeb3React();
    const autoRouterSupported = useAutoRouterSupported();
    const inputs = useMemo(()=>[
            amountSpecified,
            otherCurrency
        ], [
        amountSpecified,
        otherCurrency
    ]);
    const isDebouncing = useDebounce(inputs, DEBOUNCE_TIME) !== inputs;
    const isWrap = useMemo(()=>{
        if (!chainId || !amountSpecified || !otherCurrency) return false;
        const weth = WRAPPED_NATIVE_CURRENCY[chainId];
        return Boolean(amountSpecified.currency.isNative && weth?.equals(otherCurrency) || otherCurrency.isNative && weth?.equals(amountSpecified.currency));
    }, [
        amountSpecified,
        chainId,
        otherCurrency
    ]);
    const routerPreference = RouterPreference.CLIENT;
    const skipBothFetches = !autoRouterSupported || isWrap;
    const skipRoutingFetch = skipBothFetches || isDebouncing;
    const routingApiTradeResult = useRoutingAPITrade(skipRoutingFetch, tradeType, amountSpecified, otherCurrency, routerPreferenceOverride ?? routerPreference, account, inputTax, outputTax);
    return routingApiTradeResult;
}
