import { createSlice } from '@reduxjs/toolkit';
import { deletePersistedConnectionMeta, getPersistedConnectionMeta } from 'connection/meta';
import { DEFAULT_DEADLINE_FROM_NOW } from '../../constants/misc';
import { SlippageTolerance } from './types';
const selectedWallet = getPersistedConnectionMeta()?.type;
const currentTimestamp = ()=>new Date().getTime();
function pairKey(token0Address, token1Address) {
    return `${token0Address};${token1Address}`;
}
export const initialState = {
    selectedWallet,
    userLocale: null,
    userHideClosedPositions: false,
    userSlippageTolerance: SlippageTolerance.Auto,
    userSlippageToleranceHasBeenMigratedToAuto: true,
    userDeadline: DEFAULT_DEADLINE_FROM_NOW,
    tokens: {},
    pairs: {},
    timestamp: currentTimestamp(),
    hideBaseWalletBanner: false,
    showSurveyPopup: undefined
};
const userSlice = createSlice({
    name: 'user',
    initialState,
    reducers: {
        updateSelectedWallet (state, { payload: { wallet } }) {
            if (!wallet) {
                deletePersistedConnectionMeta();
            }
            state.selectedWallet = wallet;
        },
        updateUserLocale (state, action) {
            if (action.payload.userLocale !== state.userLocale) {
                state.userLocale = action.payload.userLocale;
                state.timestamp = currentTimestamp();
            }
        },
        updateUserSlippageTolerance (state, action) {
            state.userSlippageTolerance = action.payload.userSlippageTolerance;
            state.timestamp = currentTimestamp();
        },
        updateUserDeadline (state, action) {
            state.userDeadline = action.payload.userDeadline;
            state.timestamp = currentTimestamp();
        },
        updateHideClosedPositions (state, action) {
            state.userHideClosedPositions = action.payload.userHideClosedPositions;
        },
        updateHideBaseWalletBanner (state, action) {
            state.hideBaseWalletBanner = action.payload.hideBaseWalletBanner;
        },
        addSerializedToken (state, { payload: { serializedToken } }) {
            if (!state.tokens) {
                state.tokens = {};
            }
            state.tokens[serializedToken.chainId] = state.tokens[serializedToken.chainId] || {};
            state.tokens[serializedToken.chainId][serializedToken.address] = serializedToken;
            state.timestamp = currentTimestamp();
        },
        addSerializedPair (state, { payload: { serializedPair } }) {
            if (serializedPair.token0.chainId === serializedPair.token1.chainId && serializedPair.token0.address !== serializedPair.token1.address) {
                const chainId = serializedPair.token0.chainId;
                state.pairs[chainId] = state.pairs[chainId] || {};
                state.pairs[chainId][pairKey(serializedPair.token0.address, serializedPair.token1.address)] = serializedPair;
            }
            state.timestamp = currentTimestamp();
        }
    }
});
export const { addSerializedPair, addSerializedToken, updateSelectedWallet, updateHideClosedPositions, updateUserDeadline, updateUserLocale, updateUserSlippageTolerance, updateHideBaseWalletBanner } = userSlice.actions;
export default userSlice.reducer;
