import { useMemo } from "react";
import useStablecoinPrice from "./useStablecoinPrice";
export function useUSDPrice(currencyAmount) {
    // Use USDC-based pricing for chains.
    const stablecoinPrice = useStablecoinPrice(currencyAmount?.currency);
    return useMemo(()=>{
        if (currencyAmount && stablecoinPrice) {
            return {
                data: parseFloat(stablecoinPrice.quote(currencyAmount).toSignificant()),
                isLoading: false
            };
        } else {
            return {
                data: undefined,
                isLoading: false
            };
        }
    }, [
        currencyAmount,
        stablecoinPrice
    ]);
}
