import { AllowanceTransfer, MaxAllowanceTransferAmount, PERMIT2_ADDRESS } from "@uniswap/permit2-sdk";
import { CurrencyAmount } from "@vanadex/sdk-core";
import { useWeb3React } from "@web3-react/core";
import PERMIT2_ABI from "abis/permit2.json";
import { useContract } from "hooks/useContract";
import { useSingleCallResult } from "lib/hooks/multicall";
import ms from "ms";
import { useCallback, useEffect, useMemo, useState } from "react";
import { toReadableError, UserRejectedRequestError } from "utils/errors";
import { signTypedData } from "utils/signing";
import { didUserReject } from "utils/swapErrorToUserReadableMessage";
const PERMIT_EXPIRATION = ms(`30d`);
const PERMIT_SIG_EXPIRATION = ms(`30m`);
function toDeadline(expiration) {
    return Math.floor((Date.now() + expiration) / 1000);
}
export function usePermitAllowance(token, owner, spender) {
    const contract = useContract(PERMIT2_ADDRESS, PERMIT2_ABI);
    const inputs = useMemo(()=>[
            owner,
            token?.address,
            spender
        ], [
        owner,
        spender,
        token?.address
    ]);
    // If there is no allowance yet, re-check next observed block.
    // This guarantees that the permitAllowance is synced upon submission and updated upon being synced.
    const [blocksPerFetch, setBlocksPerFetch] = useState();
    const result = useSingleCallResult(contract, "allowance", inputs, {
        blocksPerFetch
    }).result;
    const rawAmount = result?.amount.toString(); // convert to a string before using in a hook, to avoid spurious rerenders
    const allowance = useMemo(()=>token && rawAmount ? CurrencyAmount.fromRawAmount(token, rawAmount) : undefined, [
        token,
        rawAmount
    ]);
    useEffect(()=>setBlocksPerFetch(allowance?.equalTo(0) ? 1 : undefined), [
        allowance
    ]);
    return useMemo(()=>({
            permitAllowance: allowance,
            expiration: result?.expiration,
            nonce: result?.nonce
        }), [
        allowance,
        result?.expiration,
        result?.nonce
    ]);
}
export function useUpdatePermitAllowance(token, spender, nonce, onPermitSignature) {
    const { account, chainId, provider } = useWeb3React();
    return useCallback(async ()=>{
        try {
            if (!chainId) throw new Error("missing chainId");
            if (!provider) throw new Error("missing provider");
            if (!token) throw new Error("missing token");
            if (!spender) throw new Error("missing spender");
            if (nonce === undefined) throw new Error("missing nonce");
            const permit = {
                details: {
                    token: token.address,
                    amount: MaxAllowanceTransferAmount,
                    expiration: toDeadline(PERMIT_EXPIRATION),
                    nonce
                },
                spender,
                sigDeadline: toDeadline(PERMIT_SIG_EXPIRATION)
            };
            const { domain, types, values } = AllowanceTransfer.getPermitData(permit, PERMIT2_ADDRESS, chainId);
            const signature = await signTypedData(provider.getSigner(account), domain, types, values);
            onPermitSignature?.({
                ...permit,
                signature
            });
            return;
        } catch (e) {
            const symbol = token?.symbol ?? "Token";
            if (didUserReject(e)) {
                throw new UserRejectedRequestError(`${symbol} permit allowance failed: User rejected signature`);
            }
            throw toReadableError(`${symbol} permit allowance failed:`, e);
        }
    }, [
        account,
        chainId,
        nonce,
        onPermitSignature,
        provider,
        spender,
        token
    ]);
}
