import { Interface } from '@ethersproject/abi';
import { CurrencyAmount } from '@vanadex/sdk-core';
import { useWeb3React } from '@web3-react/core';
import ERC20ABI from 'abis/erc20.json';
import JSBI from 'jsbi';
import { useMultipleContractSingleData, useSingleContractMultipleData } from 'lib/hooks/multicall';
import { useMemo } from 'react';
import { nativeOnChain } from '../../constants/tokens';
import { useInterfaceMulticall } from '../../hooks/useContract';
import { isAddress } from '../../utils';
/**
 * Returns a map of the given addresses to their eventually consistent ETH balances.
 */ function useNativeCurrencyBalances(uncheckedAddresses) {
    const { chainId } = useWeb3React();
    const multicallContract = useInterfaceMulticall();
    const validAddressInputs = useMemo(()=>uncheckedAddresses ? uncheckedAddresses.map(isAddress).filter((a)=>a !== false).sort().map((addr)=>[
                addr
            ]) : [], [
        uncheckedAddresses
    ]);
    const results = useSingleContractMultipleData(multicallContract, 'getEthBalance', validAddressInputs);
    return useMemo(()=>validAddressInputs.reduce((memo, [address], i)=>{
            const value = results?.[i]?.result?.[0];
            if (value && chainId) memo[address] = CurrencyAmount.fromRawAmount(nativeOnChain(chainId), JSBI.BigInt(value.toString()));
            return memo;
        }, {}), [
        validAddressInputs,
        chainId,
        results
    ]);
}
const ERC20Interface = new Interface(ERC20ABI);
const tokenBalancesGasRequirement = {
    gasRequired: 185000
};
/**
 * Returns a map of token addresses to their eventually consistent token balances for a single account.
 */ export function useTokenBalancesWithLoadingIndicator(address, tokens) {
    const { chainId } = useWeb3React() // we cannot fetch balances cross-chain
    ;
    const validatedTokens = useMemo(()=>tokens?.filter((t)=>isAddress(t?.address) !== false && t?.chainId === chainId) ?? [], [
        chainId,
        tokens
    ]);
    const validatedTokenAddresses = useMemo(()=>validatedTokens.map((vt)=>vt.address), [
        validatedTokens
    ]);
    const balances = useMultipleContractSingleData(validatedTokenAddresses, ERC20Interface, 'balanceOf', useMemo(()=>[
            address
        ], [
        address
    ]), tokenBalancesGasRequirement);
    const anyLoading = useMemo(()=>balances.some((callState)=>callState.loading), [
        balances
    ]);
    return useMemo(()=>[
            address && validatedTokens.length > 0 ? validatedTokens.reduce((memo, token, i)=>{
                const value = balances?.[i]?.result?.[0];
                const amount = value ? JSBI.BigInt(value.toString()) : undefined;
                if (amount) {
                    memo[token.address] = CurrencyAmount.fromRawAmount(token, amount);
                }
                return memo;
            }, {}) : {},
            anyLoading
        ], [
        address,
        validatedTokens,
        anyLoading,
        balances
    ]);
}
export function useTokenBalances(address, tokens) {
    return useTokenBalancesWithLoadingIndicator(address, tokens)[0];
}
// get the balance for a single token/account combo
export function useTokenBalance(account, token) {
    const tokenBalances = useTokenBalances(account, useMemo(()=>[
            token
        ], [
        token
    ]));
    if (!token) return undefined;
    return tokenBalances[token.address];
}
export function useCurrencyBalances(account, currencies) {
    const tokens = useMemo(()=>currencies?.filter((currency)=>currency?.isToken ?? false) ?? [], [
        currencies
    ]);
    const { chainId } = useWeb3React();
    const tokenBalances = useTokenBalances(account, tokens);
    const containsETH = useMemo(()=>currencies?.some((currency)=>currency?.isNative) ?? false, [
        currencies
    ]);
    const ethBalance = useNativeCurrencyBalances(useMemo(()=>containsETH ? [
            account
        ] : [], [
        containsETH,
        account
    ]));
    return useMemo(()=>currencies?.map((currency)=>{
            if (!account || !currency || currency.chainId !== chainId) return undefined;
            if (currency.isToken) return tokenBalances[currency.address];
            if (currency.isNative) return ethBalance[account];
            return undefined;
        }) ?? [], [
        account,
        chainId,
        currencies,
        ethBalance,
        tokenBalances
    ]);
}
export default function useCurrencyBalance(account, currency) {
    return useCurrencyBalances(account, useMemo(()=>[
            currency
        ], [
        currency
    ]))[0];
}
